  var pad = function (n) { return (n < 10 ? '0' : '') + n }
  var now = new Date()
  var today = now.getFullYear() + '-' + pad(now.getMonth() + 1) + '-' + pad(now.getDate())
  var byDispSeqThenRegDesc = function (a, b) {
    var sa = a.legacyDispSeq == null ? 10 : a.legacyDispSeq
    var sb = b.legacyDispSeq == null ? 10 : b.legacyDispSeq
    if (sa !== sb) return sa - sb
    var reg = String(b.reg || '').localeCompare(String(a.reg || ''))
    if (reg !== 0) return reg
    return String(a.id).localeCompare(String(b.id))
  }
  var def = C.collections.eventPosts
  var seen = {}
  def.rows.forEach(function (row) { seen[row.id] = true })
  /* 진행상태 — 레거시 board.php CASE와 동일 규칙(소식 출신 글은 기간이 없어 기본 종료) */
  var incoming = eventRows.filter(function (row) { return !seen[row.id] }).map(function (row) {
    var status = '종료'
    if (row.start && row.start > today) status = '예정'
    else if (row.end && row.end >= today) status = '진행중'
    return Object.assign({}, row, { status: status })
  })
  var merged = def.rows.concat(incoming)
  merged.sort(byDispSeqThenRegDesc)
  def.rows = merged.map(function (row, index) { return Object.assign({}, row, { seq: index + 1 }) })
  def.description += ' 비앤빛 소식(B_1_1)에서 분리한 이벤트성 글 ' + eventRows.length + '건이 병합되어 있습니다.'
